import { scale } from '../../../core/main-zc-init';

export function snapChartBrush(event) {
    let plotBrush = this,
        chart = plotBrush.chart,
        selection = event.selection,
        scaleX = chart.axes.x.scale;

    if (!scaleX.bandwidth || plotBrush.options.type !== 'x' || !selection) {
        return null;
    }

    let [pos1, pos2] = selection.map(function(s0) {
            return scale.invert('ordinal', { x: s0, y: 0 }, scaleX, false, 'x');
        }),
        domain = scaleX.domain().slice(pos1, pos2 + 1, 0),
        domainRange = [domain[0], domain[domain.length - 1]];

    selection = domainRange.map(scaleX);

    // add the bandwidth to the last bar
    selection[selection.length - 1] += scaleX.bandwidth();

    return selection;
}
